extern std::string generateResponse(const std::string& input);
extern void sv(const std::string& filename);
extern void ld(const std::string& filename);
extern "C" double get_current_valence();  // returns S.current_valence from main.cpp

AGI_API::AGI_API(int port) : server_(std::make_unique<WebServer>(port)) {
    server_->register_route("POST", "/api/chat", [this](const HttpRequest& req) { return handle_chat(req); });
    server_->register_route("POST", "/api/save", [this](const HttpRequest& req) { return handle_save(req); });
    server_->register_route("POST", "/api/load", [this](const HttpRequest& req) { return handle_load(req); });
    server_->register_route("GET", "/", [this](const HttpRequest& req) { return handle_ui(req); });
}

AGI_API::~AGI_API() { stop(); }
void AGI_API::start() { server_->start(); }
void AGI_API::stop() { server_->stop(); }

std::string AGI_API::json_escape(const std::string& str) {
    std::ostringstream oss;
    for (char c : str) {
        switch (c) {
            case '"': oss << "\\\""; break;
            case '\\': oss << "\\\\"; break;
            case '\n': oss << "\\n"; break;
            case '\r': oss << "\\r"; break;
            case '\t': oss << "\\t"; break;
            default: oss << c;
        }
    }
    return oss.str();
}

std::string AGI_API::sanitize_output(const std::string& raw) {
    std::string cleaned = raw;
    
    // Remove system markers
    size_t pos = 0;
    while ((pos = cleaned.find("[SYNAPTIC]:", pos)) != std::string::npos) {
        cleaned.erase(pos, 11);  // "[SYNAPTIC]:" is 11 chars
    }
    pos = 0;  // reset before second search
    while ((pos = cleaned.find("[SYNAPTIC]", pos)) != std::string::npos) {
        cleaned.erase(pos, 10);  // "[SYNAPTIC]" is 10 chars
    }
    
    // Remove sentiment markers
    const std::string markers[] = {"[positive]", "[negative]", "[neutral]"};
    for (const auto& marker : markers) {
        pos = 0;
        while ((pos = cleaned.find(marker, pos)) != std::string::npos) {
            cleaned.erase(pos, marker.length());
        }
    }
    
    // Trim whitespace (safe against all-whitespace or empty strings)
    size_t first = cleaned.find_first_not_of(" \t\n\r");
    if (first == std::string::npos) return "";  // all whitespace
    size_t last = cleaned.find_last_not_of(" \t\n\r");
    cleaned = cleaned.substr(first, last - first + 1);
    
    // Fix common grammar issues
    if (!cleaned.empty()) {
        // Capitalize first letter
        cleaned[0] = std::toupper(cleaned[0]);
        
        // Add period if missing
        char last = cleaned.back();
        if (last != '.' && last != '!' && last != '?') {
            cleaned += '.';
        }
        
        // Fix double spaces
        pos = 0;
        while ((pos = cleaned.find("  ", pos)) != std::string::npos) {
            cleaned.replace(pos, 2, " ");
        }
        
        // Fix space before punctuation
        pos = 0;
        while ((pos = cleaned.find(" .", pos)) != std::string::npos) {
            cleaned.erase(pos, 1);
        }
        pos = 0;
        while ((pos = cleaned.find(" ,", pos)) != std::string::npos) {
            cleaned.erase(pos, 1);
        }
        pos = 0;
        while ((pos = cleaned.find(" !", pos)) != std::string::npos) {
            cleaned.erase(pos, 1);
        }
        pos = 0;
        while ((pos = cleaned.find(" ?", pos)) != std::string::npos) {
            cleaned.erase(pos, 1);
        }
    }
    
    return cleaned;
}

HttpResponse AGI_API::handle_chat(const HttpRequest& req) {
    HttpResponse resp;
    resp.status_code = 200;
    
    std::string message;
    size_t msg_pos = req.body.find("\"message\":");
    if (msg_pos != std::string::npos) {
        size_t start = req.body.find('"', msg_pos + 10) + 1;
        // Walk forward respecting backslash escapes
        size_t end = start;
        while (end < req.body.size()) {
            if (req.body[end] == '\\') { end += 2; continue; }
            if (req.body[end] == '"')  { break; }
            ++end;
        }
        // Unescape the extracted substring
        std::string raw = req.body.substr(start, end - start);
        message.reserve(raw.size());
        for (size_t i = 0; i < raw.size(); ++i) {
            if (raw[i] == '\\' && i + 1 < raw.size()) {
                ++i;
                switch (raw[i]) {
                    case '"':  message += '"';  break;
                    case '\\': message += '\\'; break;
                    case 'n':  message += '\n'; break;
                    case 'r':  message += '\r'; break;
                    case 't':  message += '\t'; break;
                    default:   message += raw[i]; break;
                }
            } else {
                message += raw[i];
            }
        }
    }
    
    try {
        std::string raw_response = generateResponse(message);
        std::string sanitized = sanitize_output(raw_response);
        
        // Capture valence after response generation — reflects Synaptic's post-response emotional state
        double valence_snapshot = get_current_valence();

        std::ostringstream oss;
        oss << std::fixed << std::setprecision(4);
        oss << "{\"status\":\"ok\",\"response\":\"" << json_escape(sanitized)
            << "\",\"valence\":" << valence_snapshot << "}";
        resp.body = oss.str();
    } catch (const std::exception& e) {
        resp.body = "{\"status\":\"error\",\"message\":\"" + json_escape(e.what()) + "\"}";
        resp.status_code = 500;
    }
    return resp;
}

HttpResponse AGI_API::handle_save(const HttpRequest&) {
    HttpResponse resp;
    resp.status_code = 200;
    try {
        sv("state.dat");
        resp.body = "{\"status\":\"saved\"}";
    } catch (const std::exception& e) {
        resp.status_code = 500;
        resp.body = "{\"status\":\"error\",\"message\":\"" + json_escape(e.what()) + "\"}";
    }
    return resp;
}

HttpResponse AGI_API::handle_load(const HttpRequest&) {
    HttpResponse resp;
    resp.status_code = 200;
    try {
        ld("state.dat");
        resp.body = "{\"status\":\"loaded\"}";
    } catch (const std::exception& e) {
        resp.status_code = 500;
        resp.body = "{\"status\":\"error\",\"message\":\"" + json_escape(e.what()) + "\"}";
    }
    return resp;
}

